**Exported functions** (following the `model.ts` pure-function pattern):

```ts
const THEMES: ReadonlyArray<ThemeDefinition> = [T3_DARK, T3_LIGHT, T3_MIDNIGHT];
const THEME_MAP = new Map<string, ThemeDefinition>(THEMES.map((t) => [t.id, t]));

export function listThemes(): ReadonlyArray<ThemeDefinition> {
  return THEMES;
}

export function getTheme(id: string): ThemeDefinition | undefined {
  return THEME_MAP.get(id);
}

export function getDefaultThemeId(): string {
  return "t3-dark";
}
```

**Note**: This module must have zero dependencies on `@t3tools/contracts` or `effect`. It is pure TypeScript with no imports, keeping the module lightweight and free of the Effect runtime.

