};

// ---------------------------------------------------------------------------
// Registry
// ---------------------------------------------------------------------------

const THEMES: ReadonlyArray<ThemeDefinition> = [T3_DARK, T3_LIGHT, T3_MIDNIGHT];

const THEME_MAP = new Map<string, ThemeDefinition>(
  THEMES.map((t) => [t.id, t]),
);

/** Return all available built-in themes. */
export function listThemes(): ReadonlyArray<ThemeDefinition> {
  return THEMES;
}

/** Look up a single theme by its `id`. Returns `undefined` for unknown ids. */
export function getTheme(id: string): ThemeDefinition | undefined {
  return THEME_MAP.get(id);
}

/** The default theme id used when nothing has been persisted. */
export function getDefaultThemeId(): string {
  return "t3-dark";
}

