import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  getDefaultThemeId,
  getTheme,
  listThemes,
  type ThemeDefinition,
} from "@t3tools/shared/themes";

type ThemeMode = "light" | "dark" | "system";

type ThemeSnapshot = {
  mode: ThemeMode;
  namedThemeId: string | null;
  systemDark: boolean;
};

const MODE_STORAGE_KEY = "t3code:theme";
const NAMED_THEME_STORAGE_KEY = "t3code:named-theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

// ---------------------------------------------------------------------------
// Module-level external store
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStoredMode(): ThemeMode {
  const raw = localStorage.getItem(MODE_STORAGE_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function getStoredNamedThemeId(): string | null {
  const raw = localStorage.getItem(NAMED_THEME_STORAGE_KEY);
  if (raw && getTheme(raw)) return raw;
  return null;
}

// ---------------------------------------------------------------------------
// One-time migration: if the user had a mode stored but no named theme yet,
// map the mode to the corresponding built-in theme so the new system picks it
// up seamlessly.
// ---------------------------------------------------------------------------
function migrateIfNeeded(): void {
  if (localStorage.getItem(NAMED_THEME_STORAGE_KEY) !== null) return;
  const mode = getStoredMode();
  if (mode === "dark") {
    localStorage.setItem(NAMED_THEME_STORAGE_KEY, "t3-dark");
  } else if (mode === "light") {
    localStorage.setItem(NAMED_THEME_STORAGE_KEY, "t3-light");
  }
  // "system" → leave null so auto-resolution kicks in
}

// ---------------------------------------------------------------------------
// Theme resolution
// ---------------------------------------------------------------------------

function resolveActiveTheme(snapshot: ThemeSnapshot): ThemeDefinition {
  // Explicit named theme takes precedence (unless mode is "system")
  if (snapshot.namedThemeId && snapshot.mode !== "system") {
    const theme = getTheme(snapshot.namedThemeId);
    if (theme) return theme;
  }

  // System / fallback: derive from mode
  const isDark =
    snapshot.mode === "dark" ||
    (snapshot.mode === "system" && snapshot.systemDark);
  return isDark
    ? getTheme("t3-dark") ?? listThemes()[0]!
    : getTheme("t3-light") ?? listThemes()[1]!;
}

// ---------------------------------------------------------------------------
// CSS application helpers
// ---------------------------------------------------------------------------

function camelToKebab(str: string): string {
  return str.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`);
}

function applyThemeColors(theme: ThemeDefinition): void {
  const style = document.documentElement.style;
  for (const [key, value] of Object.entries(theme.colors)) {
