  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  document.documentElement.classList.toggle("dark", theme.appearance === "dark");
  applyThemeColors(theme);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// ---------------------------------------------------------------------------
// Snapshot
// ---------------------------------------------------------------------------

function buildSnapshot(): ThemeSnapshot {
  const mode = getStoredMode();
  const namedThemeId = getStoredNamedThemeId();
  const systemDark = mode === "system" ? getSystemDark() : false;
  return { mode, namedThemeId, systemDark };
}

function getSnapshot(): ThemeSnapshot {
  const mode = getStoredMode();
  const namedThemeId = getStoredNamedThemeId();
  const systemDark = mode === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.mode === mode &&
    lastSnapshot.namedThemeId === namedThemeId &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { mode, namedThemeId, systemDark };
  return lastSnapshot;
}

// ---------------------------------------------------------------------------
// Apply immediately on module load to prevent flash
// ---------------------------------------------------------------------------
migrateIfNeeded();
applyThemeDom(resolveActiveTheme(buildSnapshot()));

// ---------------------------------------------------------------------------
// External store subscription
// ---------------------------------------------------------------------------

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStoredMode() === "system") {
      applyThemeDom(resolveActiveTheme(buildSnapshot()), true);
    }
    emitChange();
  };
