import type { ThemeDefinition } from "@t3tools/shared/themes";
import { cn } from "~/lib/utils";
import { useTheme } from "~/hooks/useTheme";

// ---------------------------------------------------------------------------
// ThemeSwatch – a single selectable theme option with a color preview
// ---------------------------------------------------------------------------

function ThemeSwatch({
  theme,
  selected,
  onClick,
}: {
  theme: ThemeDefinition;
  selected: boolean;
  onClick: () => void;
}) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      className={cn(
        "flex w-full items-start gap-3 rounded-lg border px-3 py-2 text-left transition-colors",
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent",
      )}
      onClick={onClick}
    >
      {/* Mini color swatch: sidebar | editor | terminal */}
      <div className="flex shrink-0 overflow-hidden rounded-md border border-border">
        <div className="h-8 w-4" style={{ background: theme.colors.sidebar }} />
        <div className="h-8 w-6" style={{ background: theme.colors.editor }} />
        <div className="h-8 w-4" style={{ background: theme.colors.terminal }} />
      </div>

      <span className="flex flex-col">
        <span className="text-sm font-medium">{theme.name}</span>
        <span className="text-xs capitalize">{theme.appearance} theme</span>
      </span>

      {selected ? (
        <span className="ml-auto shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Active
        </span>
      ) : null}
    </button>
  );
}

// ---------------------------------------------------------------------------
// ThemeSelector – radiogroup of all available themes
// ---------------------------------------------------------------------------

export function ThemeSelector() {
  const { activeTheme, setNamedTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme">
      {availableThemes.map((t) => (
        <ThemeSwatch
          key={t.id}
          theme={t}
          selected={activeTheme.id === t.id}
          onClick={() => setNamedTheme(t.id)}
        />
      ))}
    </div>
  );
}

