import { describe, expect, it } from "vitest";

import { getDefaultThemeId, getTheme, listThemes } from "./themes";

describe("listThemes", () => {
  it("returns at least 3 built-in themes", () => {
    expect(listThemes().length).toBeGreaterThanOrEqual(3);
  });

  it("includes t3-dark, t3-light, and t3-midnight", () => {
    const ids = listThemes().map((t) => t.id);
    expect(ids).toContain("t3-dark");
    expect(ids).toContain("t3-light");
    expect(ids).toContain("t3-midnight");
  });

  it("returns a frozen array (same reference on repeated calls)", () => {
    expect(listThemes()).toBe(listThemes());
  });
});

describe("getTheme", () => {
  it("returns t3-dark with correct metadata", () => {
    const theme = getTheme("t3-dark");
    expect(theme).toBeDefined();
    expect(theme!.name).toBe("T3 Dark");
    expect(theme!.appearance).toBe("dark");
  });

  it("returns t3-light with correct metadata", () => {
    const theme = getTheme("t3-light");
    expect(theme).toBeDefined();
    expect(theme!.name).toBe("T3 Light");
    expect(theme!.appearance).toBe("light");
  });

  it("returns t3-midnight with correct metadata", () => {
    const theme = getTheme("t3-midnight");
    expect(theme).toBeDefined();
    expect(theme!.name).toBe("T3 Midnight");
    expect(theme!.appearance).toBe("dark");
  });

  it("returns undefined for unknown id", () => {
    expect(getTheme("nonexistent")).toBeUndefined();
  });
});

describe("getDefaultThemeId", () => {
  it("returns t3-dark", () => {
    expect(getDefaultThemeId()).toBe("t3-dark");
  });

  it("corresponds to an existing theme", () => {
    expect(getTheme(getDefaultThemeId())).toBeDefined();
  });
});

describe("theme color completeness", () => {
  const REQUIRED_COLOR_KEYS = [
    "background",
    "foreground",
    "card",
    "cardForeground",
    "primary",
    "primaryForeground",
    "border",
    "sidebar",
    "sidebarForeground",
    "editor",
    "editorForeground",
    "terminal",
    "terminalForeground",
    "statusBar",
    "statusBarForeground",
  ] as const;

  for (const theme of listThemes()) {
    it(`${theme.id} has all required color keys`, () => {
      for (const key of REQUIRED_COLOR_KEYS) {
        expect(theme.colors[key], `${theme.id}.colors.${key}`).toBeTruthy();
      }
    });
  }

  for (const theme of listThemes()) {
    it(`${theme.id} has a valid appearance`, () => {
      expect(["light", "dark"]).toContain(theme.appearance);
    });

    it(`${theme.id} has fontFamily and fontSize`, () => {
      expect(theme.fontFamily).toBeTruthy();
      expect(theme.fontSize).toBeGreaterThan(0);
    });
  }
});

