import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  getDefaultThemeId,
  getTheme,
  listThemes,
  type ThemeDefinition,
} from "@t3tools/shared/themes";

type ThemeMode = "light" | "dark" | "system";

type ThemeSnapshot = {
  mode: ThemeMode;
  namedThemeId: string | null;
  systemDark: boolean;
};

const MODE_STORAGE_KEY = "t3code:theme";
const NAMED_THEME_STORAGE_KEY = "t3code:named-theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

// ---------------------------------------------------------------------------
// Module-level external store
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStoredMode(): ThemeMode {
  const raw = localStorage.getItem(MODE_STORAGE_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function getStoredNamedThemeId(): string | null {
  const raw = localStorage.getItem(NAMED_THEME_STORAGE_KEY);
  if (raw && getTheme(raw)) return raw;
  return null;
}

// ---------------------------------------------------------------------------
// One-time migration: if the user had a mode stored but no named theme yet,
// map the mode to the corresponding built-in theme so the new system picks it
// up seamlessly.
// ---------------------------------------------------------------------------
function migrateIfNeeded(): void {
  if (localStorage.getItem(NAMED_THEME_STORAGE_KEY) !== null) return;
  const mode = getStoredMode();
  if (mode === "dark") {
    localStorage.setItem(NAMED_THEME_STORAGE_KEY, "t3-dark");
  } else if (mode === "light") {
    localStorage.setItem(NAMED_THEME_STORAGE_KEY, "t3-light");
  }
  // "system" → leave null so auto-resolution kicks in
}

// ---------------------------------------------------------------------------
// Theme resolution
// ---------------------------------------------------------------------------

function resolveActiveTheme(snapshot: ThemeSnapshot): ThemeDefinition {
  // Explicit named theme takes precedence (unless mode is "system")
  if (snapshot.namedThemeId && snapshot.mode !== "system") {
    const theme = getTheme(snapshot.namedThemeId);
    if (theme) return theme;
  }

  // System / fallback: derive from mode
  const isDark =
    snapshot.mode === "dark" ||
    (snapshot.mode === "system" && snapshot.systemDark);
  return isDark
    ? getTheme("t3-dark") ?? listThemes()[0]!
    : getTheme("t3-light") ?? listThemes()[1]!;
}

// ---------------------------------------------------------------------------
// CSS application helpers
// ---------------------------------------------------------------------------

function camelToKebab(str: string): string {
  return str.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`);
}

function applyThemeColors(theme: ThemeDefinition): void {
  const style = document.documentElement.style;
  for (const [key, value] of Object.entries(theme.colors)) {
    style.setProperty(`--${camelToKebab(key)}`, value);
  }
}

function applyThemeDom(theme: ThemeDefinition, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  document.documentElement.classList.toggle("dark", theme.appearance === "dark");
  applyThemeColors(theme);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// ---------------------------------------------------------------------------
// Snapshot
// ---------------------------------------------------------------------------

function buildSnapshot(): ThemeSnapshot {
  const mode = getStoredMode();
  const namedThemeId = getStoredNamedThemeId();
  const systemDark = mode === "system" ? getSystemDark() : false;
  return { mode, namedThemeId, systemDark };
}

function getSnapshot(): ThemeSnapshot {
  const mode = getStoredMode();
  const namedThemeId = getStoredNamedThemeId();
  const systemDark = mode === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.mode === mode &&
    lastSnapshot.namedThemeId === namedThemeId &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { mode, namedThemeId, systemDark };
  return lastSnapshot;
}

// ---------------------------------------------------------------------------
// Apply immediately on module load to prevent flash
// ---------------------------------------------------------------------------
migrateIfNeeded();
applyThemeDom(resolveActiveTheme(buildSnapshot()));

// ---------------------------------------------------------------------------
// External store subscription
// ---------------------------------------------------------------------------

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStoredMode() === "system") {
      applyThemeDom(resolveActiveTheme(buildSnapshot()), true);
    }
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === MODE_STORAGE_KEY || e.key === NAMED_THEME_STORAGE_KEY) {
      applyThemeDom(resolveActiveTheme(buildSnapshot()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const activeTheme = resolveActiveTheme(snapshot);

  const resolvedTheme: "light" | "dark" = activeTheme.appearance;

  // Set the light/dark/system mode (preserves legacy behavior)
  const setTheme = useCallback((next: ThemeMode) => {
    localStorage.setItem(MODE_STORAGE_KEY, next);
    // When switching to system mode, clear named theme so auto-resolution kicks in
    if (next === "system") {
      localStorage.removeItem(NAMED_THEME_STORAGE_KEY);
    }
    applyThemeDom(resolveActiveTheme(buildSnapshot()), true);
    emitChange();
  }, []);

  // Select a specific named theme
  const setNamedTheme = useCallback((id: string) => {
    const theme = getTheme(id);
    if (!theme) return;
    localStorage.setItem(NAMED_THEME_STORAGE_KEY, id);
    // Update mode to match the theme's appearance so legacy consumers stay correct
    localStorage.setItem(MODE_STORAGE_KEY, theme.appearance);
    applyThemeDom(theme, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyThemeDom(activeTheme);
  }, [activeTheme]);

  return {
    /** Legacy mode: "light" | "dark" | "system" */
    theme: snapshot.mode,
    /** Legacy setter for mode */
    setTheme,
    /** Resolved appearance: "light" | "dark" */
    resolvedTheme,

    /** The fully resolved ThemeDefinition currently active */
    activeTheme,
    /** The explicitly selected named theme id, or null when in system/auto mode */
    namedThemeId: snapshot.namedThemeId,
    /** Select a named theme by id */
    setNamedTheme,
    /** All available themes */
    availableThemes: listThemes(),
  } as const;
}

